package main

import (
	"fmt"

	"github.com/malcolmston/algebra"
	"github.com/malcolmston/algebra/matrix"
)

func main() {
	// Symbolic 2x2 determinant.
	a := algebra.Sym("a")
	b := algebra.Sym("b")
	c := algebra.Sym("c")
	d := algebra.Sym("d")
	m := matrix.FromExpr([][]algebra.Expr{{a, b}, {c, d}})
	det, _ := m.Det()
	fmt.Println(det)
}

